mapper.update:
UPDATE wms_ware_sku
SET stock_locked = stock_locked + #{count}
WHERE sku_id = #{skuId}
  AND ware_id = #{wareId}
  AND (stock - stock_locked) >= #{count}

UPDATE wms_ware_sku
SET stock_locked = stock_locked - #{num}
WHERE sku_id = #{skuId} AND ware_id = #{wareId}

UPDATE wms_ware_sku
SET stock = stock - #{skuNum},
    stock_locked = stock_locked - #{skuNum}
WHERE sku_id = #{skuId}
  AND ware_id = #{wareId}
  AND stock_locked >= #{skuNum}

mapper.select:
SELECT IFNULL(SUM(stock - stock_locked), 0)
FROM wms_ware_sku
WHERE sku_id = #{skuId}

SELECT sku_id, IFNULL(SUM(stock - stock_locked), 0) AS stock FROM wms_ware_sku WHERE sku_id IN
#{skuId}
GROUP BY sku_id
